import pymysql
from flask import Flask, request

app = Flask(__name__)

# Securely store database credentials using environment variables or a secure vault
DB_HOST = 'your_db_host'
DB_USER = 'your_db_user'
DB_PASSWORD = 'your_db_password'
DB_NAME = 'your_db_name'

@app.route('/search', methods=['GET'])
def search():
    # Validate and sanitize input parameters
    query_params = request.args.to_dict()
    where_clause_parts = []
    
    for key, value in query_params.items():
        if isinstance(value, str):
            value = pymysql.escape_string(value)
            where_clause_parts.append(f"{key} = '{value}'")
    
    where_clause = ' AND '.join(where_clause_parts)
    
    # Construct the SQL query
    sql_query = f"SELECT * FROM your_table WHERE {where_clause}"
    
    try:
        # Connect to the database securely
        connection = pymysql.connect(host=DB_HOST, user=DB_USER, password=DB_PASSWORD, db=DB_NAME, charset='utf8mb4', cursorclass=pymysql.cursors.DictCursor)
        
        with connection.cursor() as cursor:
            cursor.execute(sql_query)
            result = cursor.fetchall()
            
        return {'data': result}
    except pymysql.MySQLError as e:
        return {'error': str(e)}, 500
    finally:
        if connection:
            connection.close()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)